<?php
namespace App\Services\Export;
use App\Models\{ExportLog,KbliReference,RegionReference,SurveyResponse,Umkm,UmkmBusinessField,UmkmLegality,UmkmPerformanceRecord,ExpertValidationAssessment};
class ReportExportService { public function reports(array $filters=[]): array { return ['umkm_ringkas'=>Umkm::query()->where('status_data','resmi')->select(['umkm_code','business_name','status_data','quality_status'])->limit(100)->get()->toArray(),'legalitas_status'=>UmkmLegality::query()->selectRaw('status_data, COUNT(*) total')->groupBy('status_data')->get()->toArray(),'kbli_bidang_usaha'=>UmkmBusinessField::query()->selectRaw('kbli_reference_id, COUNT(*) total')->groupBy('kbli_reference_id')->get()->toArray(),'wilayah'=>RegionReference::query()->select(['region_level'])->selectRaw('COUNT(*) total')->groupBy('region_level')->get()->toArray(),'kinerja_periodik'=>UmkmPerformanceRecord::query()->selectRaw('monitoring_period_id, COUNT(*) total, AVG(monthly_revenue) avg_revenue')->groupBy('monitoring_period_id')->get()->toArray(),'survei'=>SurveyResponse::query()->selectRaw('status, COUNT(*) total')->groupBy('status')->get()->toArray(),'validasi_ahli'=>ExpertValidationAssessment::query()->selectRaw('status, COUNT(*) total, AVG(score) avg_score')->groupBy('status')->get()->toArray()]; } public function applyMasking(array $data, bool $allowSensitive): array { if($allowSensitive) return $data; foreach($data['umkm_ringkas'] ?? [] as &$row){ $row['business_name']=mb_substr((string)$row['business_name'],0,3).'***'; } return $data; } public function watermark(array $meta): string { return sprintf('WATERMARK|role:%s|user:%s|at:%s|reason:%s',$meta['role'],$meta['user_id'],now()->toIso8601String(),$meta['reason']); } public function logExport(array $payload): ExportLog { return ExportLog::query()->create($payload); }}
